package com.multilanglearner.data.network

import android.util.Log
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.*
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.RequestBody.Companion.asRequestBody
import okhttp3.RequestBody.Companion.toRequestBody
import java.io.File
import java.util.concurrent.TimeUnit
import javax.inject.Inject
import javax.inject.Singleton

@Serializable
data class WhisperResult(
    val success: Boolean,
    val text: String = "",
    val words: List<WordTimestamp> = emptyList(),
    val detectedLang: String = "",
    val error: String = ""
)

@Singleton
class WhisperService @Inject constructor() {
    private val client = OkHttpClient.Builder()
        .connectTimeout(15, TimeUnit.SECONDS)  // 减少连接超时，加快重试
        .readTimeout(600, TimeUnit.SECONDS)    // 增加读取超时，支持长音频
        .writeTimeout(120, TimeUnit.SECONDS)   // 增加写入超时
        .retryOnConnectionFailure(true)        // 启用自动重试
        .build()

    private val json = Json { ignoreUnknownKeys = true }

    // Groq API 文件大小限制（增加到 100MB，Groq 实际支持更大）
    private val MAX_FILE_SIZE = 100 * 1024 * 1024L
    private val MIN_FILE_SIZE = 1024L // 最小 1KB，避免空文件或太小的文件

    // 最大重试次数
    private val MAX_RETRIES = 3

    /**
     * Transcribe audio via Groq Whisper API
     * 优先使用 groqApiKey，其次使用 provider 为 groq 时的 apiKey
     * 添加自动重试机制
     */
    suspend fun transcribeGroq(audioFile: File, config: AIConfig, lang: String? = null): WhisperResult? {
        // 自动重试逻辑
        var lastError: Exception? = null
        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d("WhisperService", "Retry $attempt/$MAX_RETRIES")
                kotlinx.coroutines.delay(2000L * attempt) // 递增延迟
            }

            val result = transcribeGroqInternal(audioFile, config, lang)
            if (result?.success == true) {
                return result
            }
            lastError = Exception(result?.error ?: "Unknown error")
        }

        // 所有重试都失败
        return WhisperResult(
            success = false,
            error = "❌ 转录失败（已重试 $MAX_RETRIES 次）\n\n${lastError?.message ?: "未知错误"}\n\n建议：检查网络连接和 API Key 配置"
        )
    }

    /**
     * 内部转录实现
     */
    private suspend fun transcribeGroqInternal(audioFile: File, config: AIConfig, lang: String? = null): WhisperResult? {
        // 获取 Groq API Key：优先使用专门的 groqApiKey，其次检查 provider 是否为 groq
        val apiKey = config.groqApiKey.takeIf { it.isNotBlank() }
            ?: (config.apiKey.takeIf { config.provider == "groq" && it.isNotBlank() })
            ?: return WhisperResult(success = false, error = "❌ 未配置 Groq API Key\n\n请前往「AI 设置」配置 Groq API Key。\n获取 API Key：https://console.groq.com/keys")

        val whisperModel = config.whisperModel.ifBlank { "whisper-large-v3-turbo" }

        // 检查文件大小
        val fileSize = audioFile.length()
        Log.d("WhisperService", "File size: $fileSize bytes, max: $MAX_FILE_SIZE")

        // 检查最小文件大小
        if (fileSize < MIN_FILE_SIZE) {
            Log.e("WhisperService", "File too small: $fileSize bytes (min: $MIN_FILE_SIZE)")
            return WhisperResult(
                success = false,
                error = "❌ 视频文件过小\n\n文件大小: ${fileSize / 1024} KB\n最小要求: 1 KB\n\n建议：请使用包含音频内容的有效视频文件"
            )
        }

        if (fileSize > MAX_FILE_SIZE) {
            val sizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)
            val maxMB = String.format("%.2f", MAX_FILE_SIZE / 1024.0 / 1024.0)
            Log.e("WhisperService", "File too large: $sizeMB MB (max: $maxMB MB)")
            return WhisperResult(
                success = false,
                error = "❌ 视频文件过大\n\n文件大小: $sizeMB MB\nGroq 限制: $maxMB MB\n\n建议解决方案：\n1. 使用较短的视频片段\n2. 在电脑上用 ffmpeg 压缩视频\n3. 在电脑上使用 yt-dlp 只下载音频"
            )
        }

        Log.d("WhisperService", "Starting transcription with Groq Whisper: model=$whisperModel, file=${audioFile.name}, size=$fileSize")

        val bodyBuilder = MultipartBody.Builder().setType(MultipartBody.FORM)
            .addFormDataPart("file", audioFile.name, audioFile.asRequestBody("application/octet-stream".toMediaType()))
            .addFormDataPart("model", whisperModel)
            .addFormDataPart("response_format", "verbose_json")
            .addFormDataPart("timestamp_granularities[]", "word")
            .addFormDataPart("timestamp_granularities[]", "segment")
            .addFormDataPart("temperature", "0")
            .addFormDataPart("prompt", "Transcribe accurately with proper punctuation and capitalization.")

        lang?.let { bodyBuilder.addFormDataPart("language", it) }

        val request = Request.Builder()
            .url("https://api.groq.com/openai/v1/audio/transcriptions")
            .addHeader("Authorization", "Bearer $apiKey")
            .post(bodyBuilder.build())
            .build()

        return try {
            Log.d("WhisperService", "Sending request to Groq API...")
            val response = client.newCall(request).execute()

            Log.d("WhisperService", "Response code: ${response.code}")

            if (response.code != 200) {
                val errorBody = response.body?.string() ?: "Unknown error"
                Log.e("WhisperService", "API error: $errorBody")

                // 解析错误信息
                val errorMsg = try {
                    val errorJson = json.parseToJsonElement(errorBody).jsonObject
                    val errObj = errorJson["error"]?.jsonObject
                    val errMsg = errObj?.get("message")?.jsonPrimitive?.contentOrNull
                    val errType = errObj?.get("type")?.jsonPrimitive?.contentOrNull
                    val errCode = errObj?.get("code")?.jsonPrimitive?.contentOrNull

                    when {
                        errMsg?.contains("invalid_api_key", ignoreCase = true) == true ||
                        errMsg?.contains("Unauthorized", ignoreCase = true) == true ||
                        response.code == 401 ->
                            "❌ API Key 无效\n\n请检查 Groq API Key 是否正确配置\n\n获取 API Key：https://console.groq.com/keys"
                        errMsg?.contains("quota", ignoreCase = true) == true ||
                        errMsg?.contains("limit", ignoreCase = true) == true ||
                        errMsg?.contains("rate_limit", ignoreCase = true) == true ||
                        response.code == 429 ->
                            "❌ API 配额已用完\n\nGroq API 使用次数已达限制\n\n建议：\n1. 等待配额重置\n2. 更换 API Key\n3. 升级 Groq 账户"
                        errMsg?.contains("forbidden", ignoreCase = true) == true ||
                        errMsg?.contains("banned", ignoreCase = true) == true ||
                        response.code == 403 ->
                            "❌ 转录被禁止\n\n${errMsg ?: "访问被限制"}\n\n可能原因：\n1. API Key 被禁用\n2. 账户存在违规行为\n3. 内容不符合使用条款"
                        else -> "❌ 转录失败 ($response.code)\n\n${errMsg ?: errorBody}"
                    }
                } catch (e: Exception) {
                    "❌ 转录失败\n\n${errorBody.take(200)}"
                }

                return WhisperResult(success = false, error = errorMsg)
            }

            val body = response.body?.string() ?: return WhisperResult(success = false, error = "空响应")
            Log.d("WhisperService", "Response length: ${body.length}")
            Log.d("WhisperService", "Response body preview: ${body.take(500)}")

            // 检查响应是否为有效的 JSON
            if (!body.trim().startsWith("{") && !body.trim().startsWith("[")) {
                Log.e("WhisperService", "Response is not valid JSON: ${body.take(200)}")
                return WhisperResult(
                    success = false,
                    error = "❌ API 返回格式错误\n\nGroq API 返回了非 JSON 格式的响应。\n\n响应内容：\n${body.take(500)}"
                )
            }

            try {
                val jsonObj = json.parseToJsonElement(body).jsonObject
                val text = jsonObj["text"]?.jsonPrimitive?.contentOrNull ?: ""
                val detectedLang = jsonObj["language"]?.jsonPrimitive?.contentOrNull ?: ""

                Log.d("WhisperService", "Transcribed text length: ${text.length}, detected language: $detectedLang")

                val words = jsonObj["words"]?.jsonArray?.map { w ->
                    val obj = w.jsonObject
                    WordTimestamp(
                        w = obj["word"]?.jsonPrimitive?.contentOrNull ?: "",
                        s = (obj["start"]?.jsonPrimitive?.doubleOrNull ?: 0.0),
                        e = (obj["end"]?.jsonPrimitive?.doubleOrNull ?: 0.0)
                    )
                } ?: emptyList()

                Log.d("WhisperService", "Word timestamps count: ${words.size}")

                WhisperResult(
                    success = true,
                    text = text,
                    words = words,
                    detectedLang = detectedLang
                )
            } catch (e: Exception) {
                Log.e("WhisperService", "JSON parsing error", e)
                Log.e("WhisperService", "Response body: $body")
                WhisperResult(
                    success = false,
                    error = "❌ 响应解析失败\n\nGroq API 返回了无法解析的响应。\n\n错误: ${e.message}\n\n响应内容：\n${body.take(500)}"
                )
            }
        } catch (e: Exception) {
            Log.e("WhisperService", "Transcription error", e)
            val errorMsg = when {
                e.message?.contains("timeout", ignoreCase = true) == true ->
                    "❌ 请求超时\n\n网络连接超时，请检查网络连接后重试。"
                e.message?.contains("Unable to resolve host", ignoreCase = true) == true ||
                e.message?.contains("UnknownHost", ignoreCase = true) == true ->
                    "❌ 网络连接失败\n\n无法连接到 Groq API 服务器，请检查网络连接。"
                else -> "❌ 转录失败\n\n${e.message ?: "未知错误"}\n\n请检查网络连接和 API Key 配置后重试。"
            }
            WhisperResult(success = false, error = errorMsg)
        }
    }
}

package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.delay
import kotlinx.coroutines.withContext
import kotlinx.coroutines.yield
import okhttp3.OkHttpClient
import java.io.File
import java.io.IOException
import java.io.RandomAccessFile
import java.util.concurrent.TimeUnit
import java.util.concurrent.atomic.AtomicBoolean
import java.util.concurrent.atomic.AtomicLong
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段下载管理器
 * 支持大文件分段下载和断点续传
 *
 * 功能特性：
 * - 支持大文件（>100MB）分段下载
 * - 改进的断点续传（包含校验和）
 * - 详细的进度回调（分段信息、速度、剩余时间）
 * - 并发下载优化
 * - 增强的错误处理和重试机制
 * - 支持取消下载
 */
@Singleton
class SegmentedDownloader @Inject constructor() {

    private val client = OkHttpClient.Builder()
        .connectTimeout(60, TimeUnit.SECONDS)
        .readTimeout(300, TimeUnit.SECONDS) // 5分钟读超时，适合大文件下载
        .writeTimeout(300, TimeUnit.SECONDS)
        .build()

    // 每个分段的大小（5MB）
    private val SEGMENT_SIZE = 5L * 1024 * 1024

    // 最小分段大小（1MB，小于此文件不分段）
    private val MIN_SEGMENT_SIZE = 1L * 1024 * 1024

    // 大文件阈值（100MB，超过此值使用更大的分段）
    private val LARGE_FILE_THRESHOLD = 100L * 1024 * 1024

    // 大文件分段大小（10MB）
    private val LARGE_SEGMENT_SIZE = 10L * 1024 * 1024

    // 最大并发下载数
    private val MAX_CONCURRENT_DOWNLOADS = 3

    // 最大重试次数
    private val MAX_RETRY_COUNT = 5
    // 重试延迟（毫秒）
    private val RETRY_DELAY_MS = 3000L

    // 当前下载的取消标志
    private val currentCancellationFlag = AtomicBoolean(false)

    /**
     * 下载进度回调
     */
    data class DownloadProgress(
        val bytesDownloaded: Long,
        val totalBytes: Long,
        val percent: Int,
        val speed: Long, // bytes per second
        val segmentIndex: Int, // 当前分段索引（1-based）
        val totalSegments: Int, // 总分段数
        val completedSegments: Set<Int>, // 已完成的分段索引集合
        val currentSegmentBytes: Long = 0, // 当前分段已下载字节数
        val currentSegmentTotal: Long = 0, // 当前分段总字节数
        val remainingTimeSeconds: Long = 0, // 预计剩余时间（秒）
        val activeConnections: Int = 1 // 当前活跃连接数
    )

    /**
     * 下载配置
     */
    data class DownloadConfig(
        val url: String,
        val outputFile: File,
        val segmentSize: Long = 5L * 1024 * 1024, // 5MB
        val enableResume: Boolean = true,
        val maxRetries: Int = 3,
        val concurrentDownloads: Int = 3,
        val cookies: String? = null, // 添加Cookie支持
        val audioUrl: String? = null, // 音频流URL（用于DASH格式）
        val onProgress: (DownloadProgress) -> Unit = {},
        val onSegmentComplete: (segmentIndex: Int, success: Boolean) -> Unit = { _, _ -> }
    )

    /**
     * 分段状态信息
     */
    private data class SegmentState(
        val index: Int,
        val start: Long,
        val end: Long,
        val downloadedBytes: Long = 0,
        val isCompleted: Boolean = false,
        val checksum: Long = 0 // 简单校验和
    )

    /**
     * 断点续传状态
     */
    private data class ResumeState(
        val fileSize: Long,
        val segmentSize: Long,
        val segments: List<SegmentState>,
        val timestamp: Long = System.currentTimeMillis()
    )
    suspend fun download(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        try {
            Log.d("SegmentedDownloader", "Starting download: ${config.url}")

            // 如果有音频URL，使用音视频合并流程
            if (config.audioUrl != null) {
                Log.d("SegmentedDownloader", "Audio URL provided, using merge mode")
                return@withContext downloadAndMerge(config)
            }

            // 获取文件大小
            val fileSize = getContentLength(config.url)
            if (fileSize <= 0) {
                // 不支持分段下载，使用普通下载
                Log.d("SegmentedDownloader", "Segmented download not supported, using simple download")
                return@withContext simpleDownload(config)
            }

            Log.d("SegmentedDownloader", "File size: $fileSize bytes")

            // 判断是否需要分段
            if (fileSize < MIN_SEGMENT_SIZE) {
                Log.d("SegmentedDownloader", "File too small for segmentation, using simple download")
                return@withContext simpleDownload(config)
            }

            // 计算分段数量
            val segmentCount = ((fileSize + config.segmentSize - 1) / config.segmentSize).toInt()
            Log.d("SegmentedDownloader", "Splitting into $segmentCount segments")

            // 创建临时文件
            val tempFile = File(config.outputFile.absolutePath + ".tmp")
            val raf = RandomAccessFile(tempFile, "rw")
            raf.setLength(fileSize)

            // 下载每个分段
            val downloadedSegments = if (config.enableResume) {
                loadResumeState(tempFile)
            } else {
                mutableSetOf()
            }

            var totalDownloaded = 0L
            val startTime = System.currentTimeMillis()

            for (i in 0 until segmentCount) {
                if (i in downloadedSegments) {
                    Log.d("SegmentedDownloader", "Segment $i already downloaded, skipping")
                    totalDownloaded += minOf(config.segmentSize, fileSize - i * config.segmentSize)
                    continue
                }

                val start = i * config.segmentSize
                val end = minOf(start + config.segmentSize - 1, fileSize - 1)

                Log.d("SegmentedDownloader", "Downloading segment $i: $start-$end")

                try {
                    val success = downloadSegment(config.url, tempFile, start, end, config.cookies) { bytes ->
                        totalDownloaded += bytes
                        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                        val speed = if (elapsed > 0) totalDownloaded / elapsed.toLong() else 0

                        // 计算进度，确保不超过100%
                        val progress = ((totalDownloaded * 100) / fileSize).toInt().coerceAtMost(99)

                        config.onProgress(DownloadProgress(
                            bytesDownloaded = totalDownloaded,
                            totalBytes = fileSize,
                            percent = progress,
                            speed = speed,
                            segmentIndex = i + 1,
                            totalSegments = segmentCount,
                            completedSegments = downloadedSegments
                        ))
                    }

                    if (success) {
                        downloadedSegments.add(i)
                        saveResumeState(tempFile, downloadedSegments)
                    } else {
                        Log.w("SegmentedDownloader", "Segment $i download failed after retries, marking as failed")
                        // 保存断点信息，继续下一段
                        saveResumeState(tempFile, downloadedSegments)
                    }
                } catch (e: Exception) {
                    Log.e("SegmentedDownloader", "Failed to download segment $i", e)
                    // 保存断点信息，继续下一段
                    saveResumeState(tempFile, downloadedSegments)
                }
            }

            raf.close()

            // 发送100%完成进度
            config.onProgress(DownloadProgress(
                bytesDownloaded = fileSize,
                totalBytes = fileSize,
                percent = 100,
                speed = 0,
                segmentIndex = segmentCount,
                totalSegments = segmentCount,
                completedSegments = downloadedSegments.toSet()
            ))

            // 重命名为最终文件
            if (config.outputFile.exists()) {
                config.outputFile.delete()
            }
            tempFile.renameTo(config.outputFile)

            Log.d("SegmentedDownloader", "Download completed: ${config.outputFile.absolutePath}")
            Result.success(config.outputFile)
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Download failed", e)
            Result.failure(e)
        }
    }

    /**
     * 下载并合并音频和视频流（用于DASH格式）
     */
    private suspend fun downloadAndMerge(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        Log.d("SegmentedDownloader", "Starting audio+video merge download")

        val videoFile = File(config.outputFile.absolutePath + ".video.mp4")
        val audioFile = File(config.outputFile.absolutePath + ".audio.m4a")
        val mergeOutputFile = config.outputFile

        try {
            // 更新进度：准备下载
            config.onProgress(DownloadProgress(
                bytesDownloaded = 0,
                totalBytes = 100,
                percent = 0,
                speed = 0,
                segmentIndex = 0,
                totalSegments = 2,
                completedSegments = emptySet()
            ))

            // 1. 下载视频流
            Log.d("SegmentedDownloader", "Downloading video stream...")
            val videoConfig = config.copy(outputFile = videoFile, audioUrl = null)
            val videoResult = simpleDownload(videoConfig)

            if (videoResult.isFailure) {
                Log.e("SegmentedDownloader", "Failed to download video: ${videoResult.exceptionOrNull()?.message}")
                return@withContext Result.failure(videoResult.exceptionOrNull() ?: Exception("视频下载失败"))
            }

            // 更新进度：视频下载完成
            config.onProgress(DownloadProgress(
                bytesDownloaded = 50,
                totalBytes = 100,
                percent = 50,
                speed = 0,
                segmentIndex = 1,
                totalSegments = 2,
                completedSegments = setOf(0)
            ))

            // 2. 下载音频流
            Log.d("SegmentedDownloader", "Downloading audio stream...")
            val audioConfig = config.copy(outputFile = audioFile, url = config.audioUrl!!)
            val audioResult = simpleDownload(audioConfig)

            if (audioResult.isFailure) {
                Log.e("SegmentedDownloader", "Failed to download audio: ${audioResult.exceptionOrNull()?.message}")
                // 音频下载失败，仍然尝试使用视频文件
                videoFile.renameTo(mergeOutputFile)
                return@withContext Result.success(mergeOutputFile)
            }

            // 更新进度：准备合并
            config.onProgress(DownloadProgress(
                bytesDownloaded = 90,
                totalBytes = 100,
                percent = 90,
                speed = 0,
                segmentIndex = 2,
                totalSegments = 2,
                completedSegments = setOf(0, 1)
            ))

            // 3. 使用ffmpeg合并音频和视频
            Log.d("SegmentedDownloader", "Merging audio and video with ffmpeg...")
            val mergeResult = mergeAudioVideo(videoFile, audioFile, mergeOutputFile)

            if (mergeResult) {
                // 清理临时文件
                videoFile.delete()
                audioFile.delete()

                Log.d("SegmentedDownloader", "Merge completed: ${mergeOutputFile.absolutePath}")

                // 发送100%完成进度
                config.onProgress(DownloadProgress(
                    bytesDownloaded = 100,
                    totalBytes = 100,
                    percent = 100,
                    speed = 0,
                    segmentIndex = 2,
                    totalSegments = 2,
                    completedSegments = setOf(0, 1)
                ))

                Result.success(mergeOutputFile)
            } else {
                Log.e("SegmentedDownloader", "Failed to merge audio and video")
                // 合并失败，仍然尝试使用视频文件
                videoFile.renameTo(mergeOutputFile)
                audioFile.delete()
                Result.success(mergeOutputFile)
            }

        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Merge download failed", e)
            // 清理临时文件
            if (videoFile.exists()) videoFile.delete()
            if (audioFile.exists()) audioFile.delete()
            Result.failure(e)
        }
    }

    /**
     * 使用ffmpeg合并音频和视频
     */
    private suspend fun mergeAudioVideo(videoFile: File, audioFile: File, outputFile: File): Boolean = withContext(Dispatchers.IO) {
        try {
            val command = buildString {
                append("-y -i \"${videoFile.absolutePath}\" ")
                append("-i \"${audioFile.absolutePath}\" ")
                append("-c:v copy -c:a aac ")
                append("\"${outputFile.absolutePath}\"")
            }
            Log.d("SegmentedDownloader", "FFmpeg merge command: $command")

            val session = com.arthenica.ffmpegkit.FFmpegKit.execute(command)
            val returnCode = session.returnCode
            val success = (returnCode?.value == 0) && outputFile.exists() && outputFile.length() > 1024

            Log.d("SegmentedDownloader", "Merge result: $success, return code: ${returnCode?.value}")
            success
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "FFmpeg merge error", e)
            false
        }
    }

    /**
     * 简单下载（不支持分段）- 带重试机制
     */
    private suspend fun simpleDownload(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
        val maxAttempts = config.maxRetries.coerceAtLeast(MAX_RETRY_COUNT)
        var lastError: Exception? = null

        for (attempt in 0 until maxAttempts) {
            if (attempt > 0) {
                val delayMs = RETRY_DELAY_MS * attempt
                Log.d("SegmentedDownloader", "Retry $attempt/$maxAttempts, delay ${delayMs}ms")
                delay(delayMs)
            }

            try {
                return@withContext downloadOnce(config)
            } catch (e: Exception) {
                lastError = e
                val isConnectionError = e.message?.contains("connection abort", ignoreCase = true) == true ||
                                     e.message?.contains("Software caused connection abort", ignoreCase = true) == true ||
                                     e is java.net.SocketException ||
                                     e is javax.net.ssl.SSLException

                if (isConnectionError && attempt < maxAttempts - 1) {
                    Log.w("SegmentedDownloader", "Connection error (attempt ${attempt + 1}), will retry: ${e.message}")
                    // 删除可能不完整的文件
                    if (config.outputFile.exists()) {
                        config.outputFile.delete()
                    }
                    // 继续下一次尝试
                } else {
                    // 不可重试的错误或已达到最大重试次数
                    break
                }
            }
        }

        if (lastError != null) {
            Log.e("SegmentedDownloader", "Simple download failed after $maxAttempts retries", lastError)
            Result.failure(lastError)
        } else {
            Result.failure(Exception("Download failed: unknown error"))
        }
    }

    /**
     * 执行一次下载尝试
     */
    private fun downloadOnce(config: DownloadConfig): Result<File> {
        // 添加完整的 headers 避免返回 403
        val requestBuilder = okhttp3.Request.Builder()
            .url(config.url)
            .header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
            .header("Referer", getRefererFromUrl(config.url))
            .header("Accept", "*/*")
            .header("Accept-Language", "zh-CN,zh;q=0.9,en;q=0.8")
            .header("Origin", getOriginFromUrl(config.url))
            .header("Connection", "keep-alive")

        // 添加Cookie（如果提供）
        if (!config.cookies.isNullOrEmpty()) {
            requestBuilder.header("Cookie", config.cookies)
            Log.d("SegmentedDownloader", "Using custom cookies for download")
        }

        val request = requestBuilder.build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            val errorCode = response.code
            val errorDetail = when (errorCode) {
                403 -> {
                    val urlHost = try {
                        java.net.URL(config.url).host
                    } catch (e: Exception) { "未知" }

                    when {
                        urlHost.contains("bilibili") -> {
                            val hasCookie = !config.cookies.isNullOrEmpty()
                            """
                            HTTP 403 - B站下载被拒绝

                            当前状态：${if (hasCookie) "已配置Cookie" else "未配置Cookie"}

                            可能原因：
                            ${if (hasCookie) "• Cookie已过期或无效\n• 视频需要更高权限\n• 下载链接已过期" else "• 视频需要登录才能下载\n• 视频是会员专享内容\n• 下载链接已过期"}

                            解决方案：
                            ${if (hasCookie) "1. 重新配置B站Cookie（可能已过期）\n2. 检查账号是否有该视频的访问权限" else "1. 点击「下载设置」配置Cookie\n2. 确保SESSDATA填写正确"}
                            3. 或使用「导入本地视频」功能
                            4. 在电脑上使用 yt-dlp 下载后再导入
                        """.trimIndent()
                        }

                        urlHost.contains("youtube") || urlHost.contains("googlevideo") -> """
                            HTTP 403 - YouTube下载被拒绝

                            可能原因：
                            • 视频有地区限制
                            • 下载链接已过期
                            • YouTube检测到自动化下载

                            解决方案：
                            1. 稍后重试（可能是临时限制）
                            2. 使用「导入本地视频」功能
                            3. 在电脑上使用 yt-dlp 下载后再导入
                        """.trimIndent()

                        else -> """
                            HTTP 403 - 访问被拒绝

                            可能原因：
                            • 服务器拒绝访问
                            • 需要认证才能下载

                            解决方案：
                            1. 使用「导入本地视频」功能
                        """.trimIndent()
                    }
                }
                410 -> "HTTP 410 - 下载链接已过期，请重新解析视频"
                404 -> "HTTP 404 - 视频文件不存在，可能已被删除"
                else -> "HTTP $errorCode - 下载失败"
            }
            throw IOException(errorDetail)
        }

        val body = response.body ?: throw IOException("No response body")
        val inputStream = body.byteStream()
        val totalBytes = body.contentLength()
        var downloadedBytes = 0L
        val startTime = System.currentTimeMillis()

        config.outputFile.outputStream().use { output ->
            val buffer = ByteArray(8 * 1024)
            var bytes: Int

            while (inputStream.read(buffer).also { bytes = it } > 0) {
                output.write(buffer, 0, bytes)
                downloadedBytes += bytes

                val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                val speed = if (elapsed > 0) (downloadedBytes / elapsed).toLong() else 0

                if (totalBytes > 0) {
                    config.onProgress(DownloadProgress(
                        bytesDownloaded = downloadedBytes,
                        totalBytes = totalBytes,
                        percent = ((downloadedBytes * 100) / totalBytes).toInt().coerceAtMost(99),
                        speed = speed,
                        segmentIndex = 1,
                        totalSegments = 1,
                        completedSegments = emptySet()
                    ))
                }
            }
        }

        // 发送100%完成进度
        config.onProgress(DownloadProgress(
            bytesDownloaded = config.outputFile.length(),
            totalBytes = config.outputFile.length(),
            percent = 100,
            speed = 0,
            segmentIndex = 1,
            totalSegments = 1,
            completedSegments = setOf(0)
        ))

        return Result.success(config.outputFile)
    }

    /**
     * 下载单个分段 - 带重试机制
     */
    private fun downloadSegment(
        url: String,
        file: File,
        start: Long,
        end: Long,
        cookies: String?,
        onBytesDownloaded: (Long) -> Unit
    ): Boolean {
        var lastError: Exception? = null

        repeat(MAX_RETRY_COUNT) { attempt ->
            if (attempt > 0) {
                Log.d("SegmentedDownloader", "Segment $start-$end retry $attempt/$MAX_RETRY_COUNT")
                try {
                    Thread.sleep(RETRY_DELAY_MS * attempt)
                } catch (e: InterruptedException) {
                    return false
                }
            }

            try {
                // 添加完整的 headers 避免返回 403
                val requestBuilder = okhttp3.Request.Builder()
                    .url(url)
                    .header("Range", "bytes=$start-$end")
                    .header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
                    .header("Referer", getRefererFromUrl(url))
                    .header("Accept", "*/*")
                    .header("Accept-Language", "zh-CN,zh;q=0.9,en;q=0.8")
                    .header("Origin", getOriginFromUrl(url))

                // 添加Cookie（如果提供）
                if (!cookies.isNullOrEmpty()) {
                    requestBuilder.header("Cookie", cookies)
                }

                val request = requestBuilder.build()
                val response = client.newCall(request).execute()

                if (response.code !in 200..299) {
                    val errorCode = response.code
                    val urlHost = try { java.net.URL(url).host } catch (e: Exception) { "未知" }
                    val errorMsg = when (errorCode) {
                        403 -> {
                            val hasCookie = !cookies.isNullOrEmpty()
                            val isBilibili = urlHost.contains("bilibili") || urlHost.contains("bilivideo")
                            if (isBilibili) {
                                "HTTP 403 - B站下载被拒绝 ${if (hasCookie) "(已配置Cookie，可能已过期)" else "(未配置Cookie)"}"
                            } else {
                                "HTTP 403 - 下载被拒绝，可能需要Cookie或链接已过期"
                            }
                        }
                        else -> "HTTP $errorCode - 分段下载失败"
                    }
                    throw IOException("$errorMsg (segment $start-$end)")
                }

                val inputStream = response.body?.byteStream() ?: throw IOException("No response body")
                val raf = RandomAccessFile(file, "rw")
                raf.seek(start)

                val buffer = ByteArray(8 * 1024)
                var bytes: Int
                var totalBytes = 0L

                while (inputStream.read(buffer).also { bytes = it } > 0) {
                    raf.write(buffer, 0, bytes)
                    totalBytes += bytes
                    onBytesDownloaded(bytes.toLong())
                }

                raf.close()
                inputStream.close()
                return true

            } catch (e: Exception) {
                lastError = e
                val isConnectionError = e.message?.contains("connection abort", ignoreCase = true) == true ||
                                     e.message?.contains("Software caused connection abort", ignoreCase = true) == true ||
                                     e is java.net.SocketException ||
                                     e is javax.net.ssl.SSLException

                if (!isConnectionError || attempt >= MAX_RETRY_COUNT - 1) {
                    Log.e("SegmentedDownloader", "Segment $start-$end download failed", e)
                    return false
                }
                Log.w("SegmentedDownloader", "Segment $start-$end connection error, will retry: ${e.message}")
            }
        }

        Log.e("SegmentedDownloader", "Segment $start-$end failed after $MAX_RETRY_COUNT retries", lastError)
        return false
    }

    /**
     * 获取文件内容长度
     */
    private fun getContentLength(url: String): Long {
        return try {
            // 添加必要的 headers
            val request = okhttp3.Request.Builder()
                .url(url)
                .head()
                .header("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
                .header("Referer", getRefererFromUrl(url))
                .build()

            val response = client.newCall(request).execute()

            // 检查是否支持断点续传
            val acceptRanges = response.header("Accept-Ranges") == "bytes"
            val contentLength = response.body?.contentLength() ?: 0

            if (acceptRanges && contentLength > 0) {
                contentLength
            } else {
                0
            }
        } catch (e: Exception) {
            Log.w("SegmentedDownloader", "Failed to get content length", e)
            0
        }
    }

    /**
     * 保存断点状态
     */
    private fun saveResumeState(file: File, segments: Set<Int>) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            stateFile.writeText(segments.joinToString(","))
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to save resume state", e)
        }
    }

    /**
     * 加载断点状态
     */
    private fun loadResumeState(file: File): MutableSet<Int> {
        return try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                val content = stateFile.readText()
                if (content.isNotBlank()) {
                    content.split(",").mapNotNull { it.toIntOrNull() }.toMutableSet()
                } else {
                    mutableSetOf()
                }
            } else {
                mutableSetOf()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to load resume state", e)
            mutableSetOf()
        }
    }

    /**
     * 清理断点状态
     */
    fun clearResumeState(file: File) {
        try {
            val stateFile = File(file.absolutePath + ".resume")
            if (stateFile.exists()) {
                stateFile.delete()
            }
            val tempFile = File(file.absolutePath + ".tmp")
            if (tempFile.exists()) {
                tempFile.delete()
            }
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to clear resume state", e)
        }
    }

    /**
     * 取消下载并清理临时文件
     */
    fun cancelDownload(outputFile: File) {
        clearResumeState(outputFile)
    }

    /**
     * 根据URL获取对应的Referer
     * B站、YouTube等网站需要正确的Referer才能下载
     */
    private fun getRefererFromUrl(url: String): String {
        return when {
            url.contains("bilibili.com") || url.contains("b23.tv") || url.contains("bilivideo.com") -> "https://www.bilibili.com/"
            url.contains("youtube.com") || url.contains("youtu.be") || url.contains("googlevideo.com") -> "https://www.youtube.com/"
            url.contains("douyin.com") -> "https://www.douyin.com/"
            url.contains("tiktok.com") -> "https://www.tiktok.com/"
            else -> url
        }
    }

    /**
     * 根据URL获取Origin
     */
    private fun getOriginFromUrl(url: String): String {
        return when {
            url.contains("bilibili.com") || url.contains("b23.tv") || url.contains("bilivideo.com") -> "https://www.bilibili.com"
            url.contains("youtube.com") || url.contains("youtu.be") || url.contains("googlevideo.com") -> "https://www.youtube.com"
            url.contains("douyin.com") -> "https://www.douyin.com"
            url.contains("tiktok.com") -> "https://www.tiktok.com"
            else -> {
                // 从URL中提取origin
                val uri = java.net.URL(url)
                "${uri.protocol}://${uri.host}"
            }
        }
    }
}

package com.multilanglearner.data.network

import android.content.Context
import android.util.Log
import com.arthenica.ffmpegkit.FFmpegKit
import com.arthenica.ffmpegkit.FFmpegKitConfig
import com.arthenica.ffmpegkit.FFprobeKit
import com.arthenica.ffmpegkit.MediaInformationSession
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.coroutineScope
import kotlinx.coroutines.delay
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import kotlinx.coroutines.withContext
import kotlinx.coroutines.withTimeout
import java.io.File
import kotlin.text.Regex
import javax.inject.Inject
import javax.inject.Singleton

/**
 * FFmpeg 分段转录服务 - 使用 FFmpeg Kit 处理大视频文件
 *
 * 增强功能：
 * - 重试机制：每个段失败后自动重试
 * - 超时控制：防止段处理卡死
 * - 剩余时间估算：实时显示预计完成时间
 * - 进度持久化：应用崩溃后可恢复（TODO）
 *
 * 参考 GitHub 项目：
 * - WritingMinds/ffmpeg-kit: Android FFmpeg 支持
 * - gvk7/Whisper-Ffmpeg-Multi-Segment: 多段 Whisper 转录
 * - wendy7756/AI-Video-Transcriber: 20分钟分段策略
 */
@Singleton
class FFmpegSegmentedTranscriptionService @Inject constructor(
    @ApplicationContext private val context: Context,
    private val whisperService: WhisperService
) {
    companion object {
        private const val TAG = "FFmpegSegmentTrans"
        // Groq API 文件大小限制（调整为安全值）
        private const val MAX_API_FILE_SIZE = 25 * 1024 * 1024L // 25MB（Groq 实际限制）
        // 音频段目标大小（留出安全余量）
        private const val TARGET_SEGMENT_SIZE = 20 * 1024 * 1024L // 20MB
        // 分段转录的时长阈值（秒）- 超过此时长使用分段转录
        private const val SEGMENTED_TRANSCRIPTION_THRESHOLD = 300.0 // 5分钟（降低阈值）
        // 分段时长（秒）- 降低到5分钟，确保文件大小可控
        private const val SEGMENT_DURATION = 300L // 5分钟
        // 段间重叠时间（秒）
        private const val OVERLAP_DURATION = 2L
        // 临时文件目录
        private const val TEMP_DIR = "transcription_temp"
        // 最大重试次数
        private const val MAX_RETRIES = 3
        // 重试延迟（毫秒）
        private const val RETRY_DELAY_MS = 2000L
        // 段提取超时（秒）
        private const val EXTRACTION_TIMEOUT_SEC = 300L  // 5分钟超时
        // 段转录超时（秒）- 根据段长度动态计算
        private const val TRANSCRIPTION_TIMEOUT_SEC_PER_MIN = 180L // 每分钟音频最多3分钟
        // 并行处理数量 - 串行处理以避免内存问题
        private const val PARALLEL_SEGMENTS = 1
    }

    /**
     * 分段转录进度数据 - 增强版
     */
    data class SegmentProgress(
        val currentSegment: Int,
        val totalSegments: Int,
        val percent: Int,
        val message: String,
        val remainingSeconds: Long = 0,
        val estimatedCompletionTime: Long = 0,
        // 新增：详细的分段状态
        val segmentStates: Map<Int, SegmentState> = emptyMap()
    )

    /**
     * 分段状态
     */
    data class SegmentState(
        val index: Int,
        val status: SegmentStatus,
        val message: String = ""
    )

    enum class SegmentStatus {
        PENDING,       // 等待处理
        EXTRACTING,    // 提取音频中
        EXTRACTED,     // 音频提取完成
        TRANSCRIBING,  // 转录中
        COMPLETED,     // 完成
        FAILED         // 失败
    }

    /**
     * 分段转录视频
     * @param videoFile 视频文件
     * @param config AI配置
     * @param lang 视频语言代码（如 "en", "ru", "ja" 等），null 表示自动检测
     * @param onProgress 进度回调 (当前段, 总段数, 百分比, 消息, 剩余秒数)
     */
    suspend fun transcribeWithSegments(
        videoFile: File,
        config: AIConfig,
        lang: String? = null,
        onProgress: (Int, Int, Int, String, Long) -> Unit = { _, _, _, _, _ -> }
    ): WhisperResult? = withContext(Dispatchers.IO) {
        try {
            val fileSize = videoFile.length()
            val fileSizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)

            Log.d(TAG, "Starting segmented transcription: ${videoFile.name}, $fileSizeMB MB")
            onProgress(0, 1, 5, "获取视频信息...", 0)

            // 获取视频时长和详细信息
            val mediaInfo = getMediaInformation(videoFile)

            // 尝试解析时长，兼容多种格式
            val duration = try {
                val durationStr = mediaInfo?.getDuration()
                when {
                    durationStr == null -> null
                    durationStr.matches(Regex("\\d+")) -> durationStr.toLongOrNull()?.div(1000.0)
                    durationStr.matches(Regex("\\d+\\.\\d+")) -> durationStr.toDoubleOrNull()
                    else -> {
                        Log.e(TAG, "Invalid duration format: $durationStr")
                        null
                    }
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error parsing duration: $mediaInfo", e)
                null
            }

            if (duration == null) {
                Log.e(TAG, "Failed to get video duration")
                return@withContext WhisperResult(
                    success = false,
                    error = "无法读取视频时长，请确保视频文件有效。\n\nFFmpeg 错误: ${mediaInfo?.getAllProperties()}"
                )
            }

            val durationMinutes = String.format("%.1f", duration / 60.0)
            Log.d(TAG, "Video duration: $durationMinutes minutes ($duration seconds), file size: $fileSizeMB MB")

            // 判断处理策略 - 基于时长而不是文件大小
            return@withContext when {
                duration <= SEGMENTED_TRANSCRIPTION_THRESHOLD && fileSize <= MAX_API_FILE_SIZE -> {
                    // 时长较短且文件在API限制内，先压缩音频再转录
                    Log.d(TAG, "Direct transcription with compression (duration: ${duration.toInt()}s, size: ${fileSizeMB}MB)")
                    onProgress(1, 1, 10, "压缩音频...", 0)

                    // 先压缩音频
                    val compressedFile = compressAudioForTranscription(videoFile)
                    if (compressedFile == null) {
                        Log.e(TAG, "Failed to compress audio, trying original file")
                        onProgress(1, 1, 20, "直接转录中...", 0)
                        whisperService.transcribeGroq(videoFile, config, lang)
                    } else {
                        Log.d(TAG, "Audio compressed: ${compressedFile.length()} bytes")
                        onProgress(1, 1, 30, "转录中...", 0)
                        val result = whisperService.transcribeGroq(compressedFile, config, lang)
                        // 删除临时压缩文件
                        compressedFile.delete()
                        result
                    }
                }
                else -> {
                    // 时长较长或文件过大，需要分段处理
                    val reason = if (duration > SEGMENTED_TRANSCRIPTION_THRESHOLD) {
                        "video duration exceeds ${SEGMENTED_TRANSCRIPTION_THRESHOLD.toInt()/60} minutes"
                    } else {
                        "file size exceeds ${MAX_API_FILE_SIZE/1024/1024}MB"
                    }
                    Log.d(TAG, "Segmented transcription: $reason")
                    transcribeSegmentedInternal(videoFile, config, duration, lang, onProgress)
                }
            }

        } catch (e: Exception) {
            Log.e(TAG, "Transcription error", e)
            Log.e(TAG, "Error stack trace: ${e.stackTraceToString()}")
            WhisperResult(
                success = false,
                error = "❌ 转录失败\n\n错误: ${e.message}\n\n详细日志已输出到 logcat"
            )
        }
    }

    /**
     * 内部分段转录实现 - 增强版（详细进度跟踪）
     */
    private suspend fun transcribeSegmentedInternal(
        videoFile: File,
        config: AIConfig,
        duration: Double,
        lang: String?,
        onProgress: (Int, Int, Int, String, Long) -> Unit
    ): WhisperResult? {
        // 计算分段数量
        val segments = calculateSegments(duration)
        val totalSegments = segments.size

        Log.d(TAG, "Will process in $totalSegments segments (parallel: $PARALLEL_SEGMENTS)")
        onProgress(0, totalSegments, 10, "准备处理 $totalSegments 个分段...", 0)

        // 分段状态跟踪
        val segmentStates = mutableMapOf<Int, SegmentState>()
        segments.forEachIndexed { index, _ ->
            segmentStates[index] = SegmentState(index, SegmentStatus.PENDING)
        }

        // 创建临时目录
        val tempDir = File(context.cacheDir, "$TEMP_DIR${System.currentTimeMillis()}")
        tempDir.mkdirs()

        // 时间跟踪
        val startTime = System.currentTimeMillis()
        val segmentTimes = mutableMapOf<Int, Long>()

        return try {
            val allWords = mutableListOf<WordTimestamp>()
            var failedSegments = 0
            val successSegments = mutableListOf<Int>()

            // 第一步：提取所有音频段（串行，因为IO密集）
            onProgress(0, totalSegments, 15, "提取音频段...", 0)
            val segmentFiles = mutableListOf<File?>()
            segments.forEachIndexed { index, segment ->
                val segmentFile = File(tempDir, "segment_${index}.m4a")

                // 更新状态
                segmentStates[index] = SegmentState(index, SegmentStatus.EXTRACTING, "提取音频中...")
                updateProgressWithStates(0, totalSegments, 15 + (index * 20 / totalSegments),
                    "提取音频 ${index + 1}/$totalSegments...", 0, segmentStates, onProgress)

                val extractSuccess = withTimeout(EXTRACTION_TIMEOUT_SEC * 1000L) {
                    extractAudioSegmentWithRetry(videoFile, segmentFile, segment.startTime, segment.duration, index)
                }

                if (extractSuccess && segmentFile.exists()) {
                    segmentFiles.add(segmentFile)
                    segmentStates[index] = SegmentState(index, SegmentStatus.EXTRACTED, "音频已提取")
                    Log.d(TAG, "Segment $index extracted successfully")
                } else {
                    Log.e(TAG, "Failed to extract segment $index")
                    segmentFiles.add(null)
                    segmentStates[index] = SegmentState(index, SegmentStatus.FAILED, "音频提取失败")
                    failedSegments++
                }

                // 更新状态
                updateProgressWithStates(index + 1, totalSegments, 15 + ((index + 1) * 20 / totalSegments),
                    "提取完成 ${index + 1}/$totalSegments", 0, segmentStates, onProgress)
            }

            // 第二步：并行转录音频段
            updateProgressWithStates(0, totalSegments, 40, "开始转录...", 0, segmentStates, onProgress)

            val completedIndices = mutableListOf<Int>()
            val transcriptionMutex = Mutex()

            // 使用 coroutineScope 来并行处理
            val results = coroutineScope {
                // 创建分段任务
                val transcriptionJobs = segments.mapIndexed { index, segment ->
                    async(Dispatchers.IO) {
                        if (segmentFiles[index] == null) {
                            Log.e(TAG, "Skipping segment $index (file not extracted)")
                            return@async null
                        }

                        val segmentFile = segmentFiles[index]!!
                        val segmentStartTime = System.currentTimeMillis()

                        // 更新状态为转录中
                        segmentStates[index] = SegmentState(index, SegmentStatus.TRANSCRIBING, "转录中...")
                        updateProgressWithStates(completedIndices.size, totalSegments, 40,
                            "段 ${index + 1} 转录中...", 0, segmentStates, onProgress)

                        // 计算本段转录超时时间
                        val transcriptionTimeout = (segment.duration / 60.0 * TRANSCRIPTION_TIMEOUT_SEC_PER_MIN * 1000).toLong()

                        // 转录该段
                        val result = withTimeout(transcriptionTimeout) {
                            transcribeSegmentWithRetry(segmentFile, config, index, segment.duration, lang)
                        }

                        val transcriptionTime = System.currentTimeMillis() - segmentStartTime
                        segmentTimes[index] = transcriptionTime

                        if (result?.success == true) {
                            // 调整时间戳
                            val adjustedWords = result.words.map { wt ->
                                wt.copy(s = wt.s + segment.startTime, e = wt.e + segment.startTime)
                            }

                            // 线程安全地添加结果
                            transcriptionMutex.withLock {
                                // 去除重叠部分
                                if (index > 0) {
                                    val overlapThreshold = segment.startTime - OVERLAP_DURATION.toDouble()
                                    val filteredWords = adjustedWords.filter { it.s >= overlapThreshold }
                                    allWords.addAll(filteredWords)
                                } else {
                                    allWords.addAll(adjustedWords)
                                }
                                completedIndices.add(index)
                                successSegments.add(index)
                            }

                            // 删除临时段文件
                            segmentFile.delete()

                            // 更新状态为完成
                            segmentStates[index] = SegmentState(index, SegmentStatus.COMPLETED, "已完成 (${result.words.size} 词)")
                            transcriptionMutex.withLock {
                                val completedCount = completedIndices.size
                                val progress = 40 + (completedCount * 50 / totalSegments)
                                val remainingTime = estimateRemainingTime(completedCount - 1, totalSegments, segmentTimes, startTime)
                                updateProgressWithStates(completedCount, totalSegments, progress,
                                    "转录中 $completedCount/$totalSegments...", remainingTime, segmentStates, onProgress)
                            }

                            Log.d(TAG, "Segment $index transcribed: ${result.words.size} words, time=${transcriptionTime}ms")
                            result
                        } else {
                            Log.e(TAG, "Segment $index transcription failed: ${result?.error}")
                            failedSegments++

                            // 更新状态为失败
                            val errorBrief = if (result?.error?.contains("API Key") == true) "API Key错误"
                                else if (result?.error?.contains("quota") == true) "配额用尽"
                                else if (result?.error?.contains("network") == true) "网络错误"
                                else "转录失败"

                            segmentStates[index] = SegmentState(index, SegmentStatus.FAILED, errorBrief)

                            transcriptionMutex.withLock {
                                val completedCount = completedIndices.size
                                updateProgressWithStates(completedCount, totalSegments, 40 + ((completedCount + 1) * 50 / totalSegments),
                                    "段 ${index + 1} 失败: $errorBrief", 0, segmentStates, onProgress)
                            }

                            null
                        }
                    }
                }

                // 等待所有转录任务完成
                transcriptionJobs.awaitAll()
            }

            // 按时间排序所有单词
            allWords.sortBy { it.s }

            // 清理临时目录
            tempDir.deleteRecursively()

            if (allWords.isEmpty()) {
                // 所有分段都失败了 - 提供详细的失败原因
                val failedDetails = segmentStates.entries
                    .filter { it.value.status == SegmentStatus.FAILED }
                    .map { "段 ${it.key + 1}: ${it.value.message}" }
                    .joinToString("\n")

                WhisperResult(
                    success = false,
                    error = "❌ 所有分段转录失败\n\n" +
                        "总段数: $totalSegments\n" +
                        "失败: $failedSegments\n" +
                        "成功: 0\n\n" +
                        "失败详情:\n$failedDetails\n\n" +
                        "建议解决方案:\n" +
                        "1. 检查网络连接是否正常\n" +
                        "2. 确认 Groq API Key 已正确配置\n" +
                        "3. 查看是否有配额限制\n" +
                        "4. 尝试减少并发转录数量"
                )
            } else {
                // 部分或全部成功
                val sentences = buildSentences(allWords)
                val fullText = sentences.joinToString(" ")
                val totalTime = System.currentTimeMillis() - startTime

                updateProgressWithStates(totalSegments, totalSegments, 100, "转录完成！", 0, segmentStates, onProgress)

                val resultMessage = if (failedSegments > 0) {
                    "转录完成（部分失败）\n\n成功: ${successSegments.size}/$totalSegments\n失败: $failedSegments"
                } else {
                    "转录完成！\n\n成功: $totalSegments/$totalSegments 段"
                }

                Log.d(TAG, "Segmented transcription complete: ${allWords.size} words, ${sentences.size} sentences")
                Log.d(TAG, "Total time: ${formatTime(totalTime)}, Failed: $failedSegments/$totalSegments")

                WhisperResult(
                    success = true,
                    text = fullText,
                    words = allWords,
                    detectedLang = ""
                )
            }
        } catch (e: Exception) {
            tempDir.deleteRecursively()
            Log.e(TAG, "Segmented transcription error", e)
            WhisperResult(
                success = false,
                error = "分段转录失败: ${e.message}\n\n建议：检查网络连接和 API Key 配置"
            )
        }
    }

    /**
     * 更新进度（带分段状态）
     */
    private fun updateProgressWithStates(
        currentSegment: Int,
        totalSegments: Int,
        percent: Int,
        message: String,
        remainingSeconds: Long,
        segmentStates: Map<Int, SegmentState>,
        onProgress: (Int, Int, Int, String, Long) -> Unit
    ) {
        // 在消息中添加状态摘要
        val completedCount = segmentStates.values.count { it.status == SegmentStatus.COMPLETED }
        val failedCount = segmentStates.values.count { it.status == SegmentStatus.FAILED }
        val inProgressCount = segmentStates.values.count { it.status == SegmentStatus.TRANSCRIBING }

        val statusSummary = when {
            failedCount > 0 -> " (成功$completedCount, 失败$failedCount)"
            inProgressCount > 0 -> " (进行中$inProgressCount)"
            else -> ""
        }

        onProgress(currentSegment, totalSegments, percent, message + statusSummary, remainingSeconds)
    }

    /**
     * 提取音频段 - 带重试机制
     */
    private suspend fun extractAudioSegmentWithRetry(
        inputFile: File,
        outputFile: File,
        startTime: Double,
        duration: Double,
        segmentIndex: Int
    ): Boolean = withContext(Dispatchers.IO) {
        var lastError: Exception? = null

        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d(TAG, "Retrying segment $segmentIndex extraction, attempt $attempt/$MAX_RETRIES")
                delay(RETRY_DELAY_MS * attempt)
            }

            try {
                val success = extractAudioSegment(inputFile, outputFile, startTime, duration)
                if (success) return@withContext true
            } catch (e: Exception) {
                Log.w(TAG, "Segment $segmentIndex extraction attempt $attempt failed: ${e.message}")
                lastError = e
            }
        }

        Log.e(TAG, "Segment $segmentIndex extraction failed after $MAX_RETRIES retries", lastError)
        false
    }

    /**
     * 转录单个段 - 带重试机制
     */
    private suspend fun transcribeSegmentWithRetry(
        segmentFile: File,
        config: AIConfig,
        segmentIndex: Int,
        segmentDuration: Double,
        lang: String?
    ): WhisperResult? = withContext(Dispatchers.IO) {
        var lastResult: WhisperResult? = null

        repeat(MAX_RETRIES) { attempt ->
            if (attempt > 0) {
                Log.d(TAG, "Retrying segment $segmentIndex transcription, attempt $attempt/$MAX_RETRIES")
                delay(RETRY_DELAY_MS * attempt)
            }

            val result = whisperService.transcribeGroq(segmentFile, config, lang)
            if (result?.success == true) {
                return@withContext result
            }
            lastResult = result
        }

        Log.e(TAG, "Segment $segmentIndex transcription failed after $MAX_RETRIES retries")
        lastResult
    }

    /**
     * 估算剩余时间（秒）
     */
    private fun estimateRemainingTime(
        currentIndex: Int,
        totalSegments: Int,
        segmentTimes: Map<Int, Long>,
        overallStartTime: Long
    ): Long {
        if (currentIndex == 0 || segmentTimes.isEmpty()) {
            // 还没有完成任何段，预估每段需要2分钟
            return (totalSegments * 120L)
        }

        // 计算已完成段的平均时间
        val avgTimePerSegment = segmentTimes.values.average()
        val remainingSegments = totalSegments - currentIndex

        return (avgTimePerSegment * remainingSegments / 1000).toLong()
    }

    /**
     * 格式化时间显示
     */
    private fun formatTime(milliseconds: Long): String {
        val seconds = milliseconds / 1000
        return when {
            seconds < 60 -> "${seconds}秒"
            seconds < 3600 -> "${seconds / 60}分${seconds % 60}秒"
            else -> "${seconds / 3600}小时${(seconds % 3600) / 60}分"
        }
    }

    /**
     * 计算分段策略 - 使用预先计算避免浮点精度问题
     */
    private fun calculateSegments(duration: Double): List<AudioSegment> {
        val segments = mutableListOf<AudioSegment>()
        val segmentDurationSec = SEGMENT_DURATION.toDouble() // 600.0
        val overlapDurationSec = OVERLAP_DURATION.toDouble() // 5.0
        val effectiveAdvance = segmentDurationSec - overlapDurationSec // 595.0

        // 预先计算分段数量，避免无限循环
        val totalSegments = ((duration - overlapDurationSec) / effectiveAdvance).toInt().coerceAtLeast(1)

        for (index in 0 until totalSegments) {
            val startTime = index * effectiveAdvance
            val segmentDuration = if (index == totalSegments - 1) {
                // 最后一段：处理剩余所有时间
                duration - startTime
            } else {
                // 中间段：固定长度
                segmentDurationSec
            }
            segments.add(AudioSegment(index, startTime, segmentDuration))
        }

        return segments
    }

    /**
     * 提取音频段 - 使用 stream copy 避免重新编码
     */
    private suspend fun extractAudioSegment(
        inputFile: File,
        outputFile: File,
        startTime: Double,
        duration: Double
    ): Boolean = withContext(Dispatchers.IO) {
        try {
            // 确保输出目录存在
            outputFile.parentFile?.mkdirs()

            // 构建命令字符串 - 使用 -c copy 直接复制音频流，不重新编码
            val commandStr = buildString {
                append("-hide_banner -y ")
                append("-ss $startTime ")
                append("-i \"${inputFile.absolutePath}\" ")
                append("-t $duration ")
                append("-vn ")  // 不要视频
                append("-c:a copy ")  // 直接复制音频流，不重新编码
                append("\"${outputFile.absolutePath}\"")
            }

            Log.d(TAG, "FFmpeg command: ffmpeg $commandStr")
            Log.d(TAG, "Input file: ${inputFile.absolutePath}, size: ${inputFile.length()}")
            Log.d(TAG, "Output file: ${outputFile.absolutePath}")

            // 使用同步执行
            val session = FFmpegKit.execute(commandStr)

            val returnCode = session.returnCode
            val output = session.output

            Log.d(TAG, "FFmpeg return code: ${returnCode?.value}")
            if (output?.isNotEmpty() == true) {
                Log.d(TAG, "FFmpeg output: ${output.substring(0, minOf(200, output.length))}")
            }

            // 检查输出文件
            val success = (returnCode?.value == 0) && outputFile.exists() && outputFile.length() > 1024

            Log.d(TAG, "Segment extraction result: $success, file size: ${outputFile.length()}, return code: ${returnCode?.value}")
            success

        } catch (e: Exception) {
            Log.e(TAG, "Error extracting segment", e)
            false
        }
    }

    /**
     * 压缩音频文件用于转录
     * 确保文件大小符合 API 限制
     */
    private suspend fun compressAudioForTranscription(videoFile: File): File? = withContext(Dispatchers.IO) {
        try {
            val tempFile = File(context.cacheDir, "compressed_${System.currentTimeMillis()}.m4a")

            val commandStr = buildString {
                append("-hide_banner -y ")
                append("-i \"${videoFile.absolutePath}\" ")
                append("-vn ")  // 不要视频
                append("-acodec aac ")  // 使用 AAC 编码
                append("-b:a 24k ")  // 24kbps 比特率
                append("-ac 1 ")  // 单声道
                append("-ar 16000 ")  // 16kHz 采样率（Whisper 推荐的最小值）
                append("\"${tempFile.absolutePath}\"")
            }

            Log.d(TAG, "Compression command: ffmpeg $commandStr")
            val session = FFmpegKit.execute(commandStr)

            val returnCode = session.returnCode
            val success = (returnCode?.value == 0 || returnCode?.value == 1) && tempFile.exists()

            if (success) {
                Log.d(TAG, "Audio compressed: ${tempFile.length()} bytes")
                tempFile
            } else {
                Log.e(TAG, "Compression failed: return code ${returnCode?.value}")
                tempFile.delete()
                null
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error compressing audio", e)
            null
        }
    }

    /**
     * 获取视频信息
     */
    private fun getMediaInformation(file: File): com.arthenica.ffmpegkit.MediaInformation? {
        return try {
            Log.d(TAG, "Getting media information for: ${file.absolutePath}")
            val session: MediaInformationSession = FFprobeKit.getMediaInformation(file.absolutePath)

            Log.d(TAG, "FFprobe return code: ${session.returnCode?.value}")
            Log.d(TAG, "FFprobe state: ${session.state}")

            if (session.returnCode?.value == 0) {
                val info = session.mediaInformation
                Log.d(TAG, "MediaInfo - Duration: ${info?.getDuration()}")
                info
            } else {
                Log.e(TAG, "FFprobe failed with code ${session.returnCode?.value}")
                Log.e(TAG, "FFprobe output: ${session.output}")
                null
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error getting media info", e)
            Log.e(TAG, "Error stack trace: ${e.stackTraceToString()}")
            null
        }
    }

    /**
     * 从单词构建句子
     */
    private fun buildSentences(words: List<WordTimestamp>): List<String> {
        val sentences = mutableListOf<String>()
        val currentSentence = mutableListOf<String>()

        words.forEach { wt ->
            currentSentence.add(wt.w)

            // 检查句子结束
            if (wt.w.trim().matches(Regex(".*[.!?。！？]$"))) {
                sentences.add(currentSentence.joinToString(" "))
                currentSentence.clear()
            }
        }

        // 添加最后一个未完成的句子
        if (currentSentence.isNotEmpty()) {
            sentences.add(currentSentence.joinToString(" "))
        }

        return sentences
    }
}

